import Database from 'better-sqlite3';
import { join } from 'path';
var db = new Database(join(process.cwd(), 'data.db'));
// Enable foreign keys
db.pragma('foreign_keys = ON');
// Create tables
db.exec("\n  CREATE TABLE IF NOT EXISTS users (\n    id TEXT PRIMARY KEY,\n    email TEXT UNIQUE NOT NULL,\n    password TEXT NOT NULL,\n    name TEXT NOT NULL,\n    role TEXT CHECK(role IN ('admin', 'user')) NOT NULL,\n    createdAt TEXT NOT NULL,\n    updatedAt TEXT NOT NULL\n  );\n\n  CREATE TABLE IF NOT EXISTS service_accounts (\n    id TEXT PRIMARY KEY,\n    name TEXT NOT NULL,\n    type TEXT NOT NULL,\n    credentials TEXT NOT NULL,\n    logo TEXT NOT NULL,\n    maxDevices INTEGER NOT NULL,\n    createdAt TEXT NOT NULL,\n    updatedAt TEXT NOT NULL\n  );\n\n  CREATE TABLE IF NOT EXISTS subscriptions (\n    id TEXT PRIMARY KEY,\n    userId TEXT NOT NULL,\n    serviceAccountId TEXT NOT NULL,\n    startDate TEXT NOT NULL,\n    endDate TEXT NOT NULL,\n    status TEXT CHECK(status IN ('active', 'expired', 'suspended')) NOT NULL,\n    createdAt TEXT NOT NULL,\n    updatedAt TEXT NOT NULL,\n    FOREIGN KEY (userId) REFERENCES users(id) ON DELETE CASCADE,\n    FOREIGN KEY (serviceAccountId) REFERENCES service_accounts(id) ON DELETE CASCADE\n  );\n\n  CREATE TABLE IF NOT EXISTS devices (\n    id TEXT PRIMARY KEY,\n    userId TEXT NOT NULL,\n    serviceAccountId TEXT NOT NULL,\n    name TEXT NOT NULL,\n    lastAccess TEXT NOT NULL,\n    createdAt TEXT NOT NULL,\n    updatedAt TEXT NOT NULL,\n    FOREIGN KEY (userId) REFERENCES users(id) ON DELETE CASCADE,\n    FOREIGN KEY (serviceAccountId) REFERENCES service_accounts(id) ON DELETE CASCADE\n  );\n\n  CREATE TABLE IF NOT EXISTS activity_logs (\n    id TEXT PRIMARY KEY,\n    userId TEXT NOT NULL,\n    serviceAccountId TEXT NOT NULL,\n    deviceId TEXT NOT NULL,\n    action TEXT NOT NULL,\n    timestamp TEXT NOT NULL,\n    details TEXT NOT NULL,\n    FOREIGN KEY (userId) REFERENCES users(id) ON DELETE CASCADE,\n    FOREIGN KEY (serviceAccountId) REFERENCES service_accounts(id) ON DELETE CASCADE,\n    FOREIGN KEY (deviceId) REFERENCES devices(id) ON DELETE CASCADE\n  );\n");
export { db };
